"use server";

import { redirect } from "next/navigation";
import { setSession } from "@/lib/session";
import { prisma } from "@/lib/prisma";
import { hashPassword, verifyPassword } from "@/lib/password";

const MIN_PASSWORD_LENGTH = 6;

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function validateEmail(email: string): boolean {
  return EMAIL_REGEX.test(email.trim());
}

export type SignupResult =
  | { success: true; redirectTo: string }
  | { success: false; error?: string; fieldErrors?: Record<string, string> };

export async function signup(formData: FormData): Promise<SignupResult> {
  const emailRaw = formData.get("email");
  const fullNameRaw = formData.get("fullName");
  const passwordRaw = formData.get("password");
  const positionRaw = formData.get("position");
  const avatarUrlRaw = formData.get("avatarUrl");

  const fieldErrors: Record<string, string> = {};
  const email = typeof emailRaw === "string" ? emailRaw.trim() : "";
  const fullName = typeof fullNameRaw === "string" ? fullNameRaw.trim() : "";
  const password = typeof passwordRaw === "string" ? passwordRaw : "";
  const position =
    typeof positionRaw === "string" ? positionRaw.trim() || null : null;
  const avatarUrl =
    typeof avatarUrlRaw === "string" ? avatarUrlRaw.trim() || null : null;

  if (!email) {
    fieldErrors.email = "Email is required.";
  } else if (!validateEmail(email)) {
    fieldErrors.email = "Enter a valid email address.";
  }

  if (!fullName) {
    fieldErrors.fullName = "Full name is required.";
  }

  if (!password) {
    fieldErrors.password = "Password is required.";
  } else if (password.length < MIN_PASSWORD_LENGTH) {
    fieldErrors.password = `Password must be at least ${MIN_PASSWORD_LENGTH} characters.`;
  }

  if (Object.keys(fieldErrors).length > 0) {
    return { success: false, fieldErrors };
  }

  const existing = await prisma.teamMember.findUnique({
    where: { email },
  });
  if (existing) {
    return {
      success: false,
      fieldErrors: { email: "This email is already registered." },
    };
  }

  const passwordHash = await hashPassword(password);

  const member = await prisma.teamMember.create({
    data: {
      name: fullName,
      displayName: fullName,
      email,
      passwordHash,
      position,
      avatarUrl,
    },
  });

  await setSession(member.id);
  redirect("/feed");
}

export type LoginResult =
  | { success: true; redirectTo: string }
  | { success: false; error?: string; fieldErrors?: Record<string, string> };

export async function login(formData: FormData): Promise<LoginResult> {
  const fullNameRaw = formData.get("fullName");
  const passwordRaw = formData.get("password");
  const emailRaw = formData.get("email");
  const redirectToRaw = formData.get("redirectTo");

  const fieldErrors: Record<string, string> = {};
  const fullName = typeof fullNameRaw === "string" ? fullNameRaw.trim() : "";
  const password = typeof passwordRaw === "string" ? passwordRaw : "";
  const email =
    typeof emailRaw === "string" ? emailRaw.trim() || null : null;
  const redirectTo =
    typeof redirectToRaw === "string" && redirectToRaw.startsWith("/")
      ? redirectToRaw
      : "/feed";

  if (!fullName) {
    fieldErrors.fullName = "Full name is required.";
  }
  if (!password) {
    fieldErrors.password = "Password is required.";
  }

  if (Object.keys(fieldErrors).length > 0) {
    return { success: false, fieldErrors };
  }

  const normalizedName = fullName.trim();

  const members = await prisma.teamMember.findMany({
    where: {
      name: { equals: normalizedName, mode: "insensitive" },
      passwordHash: { not: null },
    },
  });

  if (members.length === 0) {
    return { success: false, error: "Invalid name or password." };
  }

  if (members.length > 1 && !email) {
    return {
      success: false,
      error:
        "Multiple accounts with this name. Please enter your email to log in.",
      fieldErrors: { email: "Email required to disambiguate." },
    };
  }

  let candidate = members[0];
  if (members.length > 1 && email) {
    const byEmail = members.find(
      (m) => m.email && m.email.toLowerCase() === email!.toLowerCase()
    );
    if (!byEmail) {
      return { success: false, error: "Invalid name or password." };
    }
    candidate = byEmail;
  }

  const valid = await verifyPassword(password, candidate.passwordHash!);
  if (!valid) {
    return { success: false, error: "Invalid name or password." };
  }

  await setSession(candidate.id);
  return { success: true, redirectTo };
}
